import React, { useEffect, useState } from "react";

const Card = ({ number }) => {
  const [value, setValue] = useState(0);
  const [sign, setSign] = useState("positive");
  const [switchable, setSwitchable] = useState(false);

  const determineCardValue = (number) => {
    if (number > 0 && number < 7) {
      setValue(number);
    } else if (number > -7 && number < 0) {
      setValue(number);
      setSign("negative");
    } else {
      setSwitchable(true);
      switch (number) {
        case 7:
          setValue(1);
          break;
        case 8:
          setValue(2);
          break;
        case 9:
          setValue(3);
          break;
        case 10:
          setValue(4);
          break;
        case 11:
          setValue(5);
          break;
        case 12:
          setValue(6);
          break;
        case 13:
          // +/- 1 or 2
          setValue(1);
          break;
        case 100:
          setValue(1);
          break;
      }
    }
  };

  useEffect(() => {
    determineCardValue(number);
  }, []);

  const switchSign = () => {
    if (switchable) {
      setValue(-value);
      if (sign === "positive") {
        setSign("negative");
      } else {
        setSign("positive");
      }
    }
  };

  const switchOneTwo = () => {
    if (switchable) {
      if (value === 1) {
        setValue(2);
      } else if (value === 2) {
        setValue(1);
      }
    }
  };

  return (
    <div className="pazaakCard">
      <p className="pazaakCardNumber">{value}</p>
      <button onClick={() => console.log(value)}></button>
    </div>
  );
};

export default Card;
